#include<bits/stdc++.h>
using namespace std;
int l[500010],r[500010];
map<long long,bool> mp;
int main()
{
    int n,q;
    scanf("%d%d",&n,&q);
    for(int i=1;i<=n;i++)
    {
        scanf("%d%d",&l[i],&r[i]);
    }
    sort(l+1,l+1+n);
    sort(r+1,r+1+n);
    long long ans=n;
    while(q--)
    {
        int x,y;
        scanf("%d%d",&x,&y);
        if(!mp[x-1])
        {
            ans+=(lower_bound(l+1,l+1+n,x)-l)-(lower_bound(r+1,r+1+n,x)-r);
            mp[x-1]=true;
        }
        if(!mp[y])
        {
            ans+=(lower_bound(l+1,l+1+n,y+1)-l)-(lower_bound(r+1,r+1+n,y+1)-r);
            mp[y]=true;
        }
        printf("%lld\n",ans);
    }
    return 0;
}
